11	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
12	const BLOCK_SIZE = 3;
13	const BLOCK_PREMIUM = 60;
14	
15	const CURSED_SURCHARGE_RATE = 0.5;
16	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
17	const HIGH_ENCHANTMENT_THRESHOLD = 5;
18	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
