22	const calculateComponentPremium = (componentCounts: Record<string, number>): number => {
23	  let premium = 0;
24	  for (const [type, count] of Object.entries(componentCounts)) {
25	    premium += count === BLOCK_SIZE
26	      ? BLOCK_PREMIUM
